@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Noto+Sans+SC:wght@300;400;500;700&display=swap');
@import url('https://fonts.googleapis.com/icon?family=Material+Icons+Round');
@import url('https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

body {
  font-family: 'Noto Sans SC', 'Inter', sans-serif;
  width: 100%;
  margin: 0;
  padding: 0;
}

::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: #cbd5e1;
  border-radius: 4px;
}

.dark ::-webkit-scrollbar-thumb {
  background: #475569;
}

.layout-container {
  width: 100%;
  max-width: 1920px;
  margin-left: auto;
  margin-right: auto;
  padding-left: 60px;
  padding-right: 60px;
}

/* ========================================
   Dashboard 通用样式系统
   ======================================== */

/* 标题样式 */
h1,
h2,
h3,
h4,
h5,
h6 {
  font-weight: 500;
  line-height: 1.3;
  color: #1e293b;
  margin: 0;
  letter-spacing: -0.02em;
}

.dark h1,
.dark h2,
.dark h3,
.dark h4,
.dark h5,
.dark h6 {
  color: #f1f5f9;
}

h1 {
  font-size: 2.5rem;
  /* 40px */
  font-weight: 600;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 1.5rem;
}

.dark h1 {
  background: linear-gradient(135deg, #818cf8 0%, #c084fc 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

h2 {
  font-size: 2rem;
  /* 32px */
  margin-bottom: 1.25rem;
}

h3 {
  font-size: 1.5rem;
  /* 24px */
  margin-bottom: 1rem;
}

h4 {
  font-size: 1.25rem;
  /* 20px */
  margin-bottom: 0.875rem;
}

h5 {
  font-size: 1.125rem;
  /* 18px */
  margin-bottom: 0.75rem;
}

h6 {
  font-size: 1rem;
  /* 16px */
  margin-bottom: 0.625rem;
}

/* 段落样式 */
p {
  font-size: 0.875rem;
  /* 14px */
  line-height: 1.7;
  color: #475569;
  margin: 0 0 1rem 0;
}

.dark p {
  color: #cbd5e1;
}

p.lead {
  font-size: 1.125rem;
  /* 18px */
  font-weight: 400;
  color: #64748b;
  line-height: 1.8;
}

.dark p.lead {
  color: #94a3b8;
}

p.small {
  font-size: 0.75rem;
  /* 12px */
  color: #64748b;
}

.dark p.small {
  color: #94a3b8;
}

/* 文本样式 */
span {
  font-size: inherit;
  color: inherit;
}

.text-primary {
  color: #667eea;
}

.dark .text-primary {
  color: #818cf8;
}

.text-secondary {
  color: #64748b;
}

.dark .text-secondary {
  color: #94a3b8;
}

.text-success {
  color: #10b981;
}

.dark .text-success {
  color: #34d399;
}

.text-warning {
  color: #f59e0b;
}

.dark .text-warning {
  color: #fbbf24;
}

.text-danger {
  color: #ef4444;
}

.dark .text-danger {
  color: #f87171;
}

.text-muted {
  color: #94a3b8;
}

.dark .text-muted {
  color: #64748b;
}

/* 文本大小工具类 */
.text-xs {
  font-size: 0.75rem;
  /* 12px */
}

.text-sm {
  font-size: 0.875rem;
  /* 14px */
}

.text-base {
  font-size: 1rem;
  /* 16px */
}

.text-lg {
  font-size: 1.125rem;
  /* 18px */
}

.text-xl {
  font-size: 1.25rem;
  /* 20px */
}

.text-2xl {
  font-size: 1.5rem;
  /* 24px */
}

/* 文本粗细 */
.font-light {
  font-weight: 300;
}

.font-normal {
  font-weight: 400;
}

.font-medium {
  font-weight: 500;
}

.font-semibold {
  font-weight: 600;
}

.font-bold {
  font-weight: 700;
}

/* Dashboard 卡片样式 */
.dashboard-card {
  background: #ffffff;
  border-radius: 16px;
  padding: 24px;
  box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px -1px rgba(0, 0, 0, 0.1);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(226, 232, 240, 0.8);
}

.dark .dashboard-card {
  background: #1e293b;
  border-color: rgba(51, 65, 85, 0.8);
  box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.3), 0 1px 2px -1px rgba(0, 0, 0, 0.3);
}

.dashboard-card:hover {
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -4px rgba(0, 0, 0, 0.1);
  transform: translateY(-2px);
}

.dark .dashboard-card:hover {
  box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.4), 0 4px 6px -4px rgba(0, 0, 0, 0.4);
}

/* 卡片标题 */
.card-title {
  font-size: 1.125rem;
  font-weight: 600;
  color: #1e293b;
  margin-bottom: 0.5rem;
}

.dark .card-title {
  color: #f1f5f9;
}

/* 卡片描述 */
.card-description {
  font-size: 0.875rem;
  color: #64748b;
  line-height: 1.6;
}

.dark .card-description {
  color: #94a3b8;
}

/* 按钮样式 */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.625rem 1.25rem;
  font-size: 0.875rem;
  font-weight: 500;
  line-height: 1.5;
  border-radius: 8px;
  border: none;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
  text-decoration: none;
  gap: 0.5rem;
}

.btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -2px rgba(0, 0, 0, 0.1);
}

.btn:active {
  transform: translateY(0);
}

.btn-primary {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: #ffffff;
}

.btn-primary:hover {
  background: linear-gradient(135deg, #5568d3 0%, #653a8b 100%);
}

.btn-secondary {
  background: #f1f5f9;
  color: #475569;
}

.dark .btn-secondary {
  background: #334155;
  color: #e2e8f0;
}

.btn-secondary:hover {
  background: #e2e8f0;
}

.dark .btn-secondary:hover {
  background: #475569;
}

.btn-outline {
  background: transparent;
  border: 1px solid #cbd5e1;
  color: #475569;
}

.dark .btn-outline {
  border-color: #475569;
  color: #e2e8f0;
}

.btn-outline:hover {
  background: #f8fafc;
  border-color: #94a3b8;
}

.dark .btn-outline:hover {
  background: #1e293b;
  border-color: #64748b;
}

/* 徽章样式 */
.badge {
  display: inline-flex;
  align-items: center;
  padding: 0.25rem 0.75rem;
  font-size: 0.75rem;
  font-weight: 500;
  line-height: 1.5;
  border-radius: 9999px;
  white-space: nowrap;
}

.badge-primary {
  background: rgba(102, 126, 234, 0.1);
  color: #667eea;
}

.dark .badge-primary {
  background: rgba(129, 140, 248, 0.15);
  color: #818cf8;
}

.badge-success {
  background: rgba(16, 185, 129, 0.1);
  color: #10b981;
}

.dark .badge-success {
  background: rgba(52, 211, 153, 0.15);
  color: #34d399;
}

.badge-warning {
  background: rgba(245, 158, 11, 0.1);
  color: #f59e0b;
}

.dark .badge-warning {
  background: rgba(251, 191, 36, 0.15);
  color: #fbbf24;
}

.badge-danger {
  background: rgba(239, 68, 68, 0.1);
  color: #ef4444;
}

.dark .badge-danger {
  background: rgba(248, 113, 113, 0.15);
  color: #f87171;
}

/* 分割线 */
.divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, #e2e8f0, transparent);
  margin: 1.5rem 0;
  border: none;
}

.dark .divider {
  background: linear-gradient(90deg, transparent, #334155, transparent);
}

/* 链接样式 */
a {
  color: #667eea;
  text-decoration: none;
  transition: color 0.2s ease;
}

.dark a {
  color: #818cf8;
}

a:hover {
  color: #5568d3;
  text-decoration: none;
}

.dark a:hover {
  color: #a5b4fc;
}

/* 激活态链接及其悬停 */
a.active:hover {
  color: #fff !important;
  opacity: 0.9;
  filter: brightness(1.1);
}

.dark a.active:hover {
  color: #fff !important;
  opacity: 1;
  filter: brightness(1.2);
}

/* 列表样式 */
ul,
ol {
  margin: 0 0 1rem 0;
  padding-left: 1.5rem;
  color: #475569;
}

.dark ul,
.dark ol {
  color: #cbd5e1;
}

li {
  margin-bottom: 0.5rem;
  line-height: 1.7;
}

/* 代码样式 */
code {
  font-family: 'Monaco', 'Courier New', monospace;
  font-size: 0.875em;
  padding: 0.125rem 0.375rem;
  background: #f1f5f9;
  border-radius: 4px;
  color: #e11d48;
}

.dark code {
  background: #334155;
  color: #fb7185;
}

/* 表格样式 */
table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 1rem;
}

th,
td {
  padding: 0.75rem 1rem;
  text-align: left;
  border-bottom: 1px solid #e2e8f0;
}

.dark th,
.dark td {
  border-bottom-color: #334155;
}

th {
  font-weight: 600;
  color: #1e293b;
  background: #f8fafc;
}

.dark th {
  color: #f1f5f9;
  background: #1e293b;
}

td {
  color: #475569;
}

.dark td {
  color: #cbd5e1;
}

tr:hover td {
  background: #f8fafc;
}

.dark tr:hover td {
  background: #1e293b;
}

