  background: rgba(251, 191, 36, 0.15);
  color: #fbbf24;
}

.badge-danger {
  background: rgba(239, 68, 68, 0.1);
  color: #ef4444;
}

.dark .badge-danger {
  background: rgba(248, 113, 113, 0.15);
  color: #f87171;
}

/* 分割线 */
.divider {
  height: 1px;
  background: linear-gradient(90deg, transparent, #e2e8f0, transparent);
  margin: 1.5rem 0;
  border: none;
}

.dark .divider {
  background: linear-gradient(90deg, transparent, #334155, transparent);
}

/* 链接样式 */
a {
  color: #667eea;
  text-decoration: none;
  transition: color 0.2s ease;
}

.dark a {
  color: #818cf8;
}

a:hover {
  color: #5568d3;
  text-decoration: none;
}

.dark a:hover {
  color: #a5b4fc;
}

/* 激活态链接及其悬停 */
a.active:hover {
  color: #fff !important;
  opacity: 0.9;
  filter: brightness(1.1);
}

.dark a.active:hover {
  color: #fff !important;
  opacity: 1;
  filter: brightness(1.2);
}

/* 列表样式 */
ul,
ol {
  margin: 0 0 1rem 0;
  padding-left: 1.5rem;
  color: #475569;
}

.dark ul,
.dark ol {
  color: #cbd5e1;
}

li {
  margin-bottom: 0.5rem;
  line-height: 1.7;
}

/* 代码样式 */
code {
  font-family: 'Monaco', 'Courier New', monospace;
  font-size: 0.875em;
  padding: 0.125rem 0.375rem;
  background: #f1f5f9;
  border-radius: 4px;
  color: #e11d48;
}

.dark code {
  background: #334155;
  color: #fb7185;
}

/* 表格样式 */
table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 1rem;
}

th,
td {
  padding: 0.75rem 1rem;
  text-align: left;
  border-bottom: 1px solid #e2e8f0;
}

.dark th,
.dark td {
  border-bottom-color: #334155;
}

th {
  font-weight: 600;
  color: #1e293b;
  background: #f8fafc;
}

.dark th {
  color: #f1f5f9;
  background: #1e293b;
}

td {
  color: #475569;
}

.dark td {
  color: #cbd5e1;
}

tr:hover td {
  background: #f8fafc;
}

.dark tr:hover td {
  background: #1e293b;
}

