const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });

  // 阻断所有外部 Google 域名
  await page.route('**/*google*', route => route.abort());
  await page.route('**/*gstatic*', route => route.abort());

  const errors = [];
  page.on('pageerror', err => errors.push('[ERR] ' + err.message));
  page.on('console', msg => { if(msg.type()==='error') errors.push('[CONSOLE] '+msg.text()); });

  await page.goto('http://localhost:3000/', { waitUntil: 'networkidle', timeout: 30000 });
  await page.waitForTimeout(2000);

  // 验证字体资源都已本地加载
  const perfEntries = await page.evaluate(() => 
    performance.getEntriesByType('resource')
      .filter(r => r.name.includes('font') || r.name.includes('woff2'))
      .map(r => r.name.split('/').pop())
  );
  console.log('已加载字体:', perfEntries.length ? perfEntries.join(', ') : '无');

  // 导航到模板管理
  await page.click('a:has-text(\"资源中心\")');
  await page.waitForTimeout(1500);
  await page.locator('a:has-text(\"模板管理\")').click();
  await page.waitForTimeout(1500);

  const rows = await page.locator('table tbody tr').count();
  console.log('模板行数:', rows);

  // 点击添加模板
  await page.locator('button:has-text(\"添加模板\")').click();
  await page.waitForTimeout(1500);
  const modal = page.locator('div[role=\"dialog\"]');
  console.log('Modal:', await modal.isVisible() ? '✅ 可见' : '❌ 不可见');

  if (await modal.isVisible()) {
    const t = await modal.innerText();
    console.log('Modal 含模板名称:', t.includes('模板名称') ? '✅' : '❌');
    console.log('Modal 含资源类型:', t.includes('资源类型') ? '✅' : '❌');
    console.log('Modal 含镜像:', t.includes('镜像') ? '✅' : '❌');
  }

  console.log('\\n错误:', errors.length ? errors.join('\\n') : '零错误 ✅');

  await browser.close();
})();
