const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });

  // 阻断 Google
  await page.route('**/*google*', route => route.abort());
  await page.route('**/*gstatic*', route => route.abort());

  await page.goto('http://localhost:3000/', { waitUntil: 'networkidle', timeout: 30000 });
  await page.waitForTimeout(3000);

  // 检查字体加载状态
  const fontStatus = await page.evaluate(() => {
    if (!document.fonts) return 'Font API not available';
    const fonts = [];
    for (const f of document.fonts) {
      fonts.push(f.family + ' - ' + f.status);
    }
    return fonts.join(' | ') || '没有已加载的字体';
  });
  console.log('字体加载状态:', fontStatus);

  // 检查资源加载
  const resources = await page.evaluate(() => 
    performance.getEntriesByType('resource')
      .map(r => ({ name: r.name.split('/').pop(), type: r.initiatorType }))
  );
  console.log('资源加载:', resources.filter(r => r.name.includes('woff2')).map(r => r.name).join(', ') || '无 woff2 资源条目');

  // 截图并测试
  await page.click('a:has-text(\"资源中心\")');
  await page.waitForTimeout(1500);
  await page.locator('a:has-text(\"模板管理\")').click();
  await page.waitForTimeout(1500);

  await page.locator('button:has-text(\"添加模板\")').click();
  await page.waitForTimeout(1000);
  await page.screenshot({ path: '/tmp/gh-local-fonts.png', fullPage: false });

  console.log('测试完成');

  await browser.close();
})();
" 2>&1
